"""
AWS Infrastructure as Code using Boto3
This example demonstrates programmatically creating CloudFormation stacks
to provision serverless infrastructure including:
- S3 buckets for input and output
- Lambda function for image processing
- IAM roles and policies
- Event trigger configuration
"""

import boto3
import json
import zipfile
import io
from botocore.exceptions import ClientError

# Initialize CloudFormation client
cf_client = boto3.client('cloudformation')
lambda_client = boto3.client('lambda')
iam_client = boto3.client('iam')
s3_client = boto3.client('s3')

STACK_NAME = "ServerlessImageProcessorStack"
REGION = "us-east-1"


def create_cloudformation_stack():
    """
    Create a CloudFormation stack for serverless image processing.
    This demonstrates Infrastructure as Code (IaC) principle.
    """
    print(f"\n=== Creating CloudFormation Stack: {STACK_NAME} ===")

    # CloudFormation template as Python dictionary (equivalent to YAML)
    template_body = {
        "AWSTemplateFormatVersion": "2010-09-09",
        "Description": "Serverless Image Processing Stack with S3 triggers",
        "Parameters": {
            "BucketNamePrefix": {
                "Type": "String",
                "Default": "image-processor",
                "Description": "Prefix for bucket names (must be globally unique)"
            }
        },
        "Resources": {
            "SourceBucket": {
                "Type": "AWS::S3::Bucket",
                "Properties": {
                    "BucketName": {
                        "Fn::Sub": "${BucketNamePrefix}-source-${AWS::AccountId}"
                    }
                }
            },
            "DestinationBucket": {
                "Type": "AWS::S3::Bucket",
                "Properties": {
                    "BucketName": {
                        "Fn::Sub": "${BucketNamePrefix}-destination-${AWS::AccountId}"
                    }
                }
            },
            "LambdaExecutionRole": {
                "Type": "AWS::IAM::Role",
                "Properties": {
                    "RoleName": {
                        "Fn::Sub": "${BucketNamePrefix}-lambda-role"
                    },
                    "AssumeRolePolicyDocument": {
                        "Version": "2012-10-17",
                        "Statement": [{
                            "Effect": "Allow",
                            "Principal": {
                                "Service": "lambda.amazonaws.com"
                            },
                            "Action": "sts:AssumeRole"
                        }]
                    },
                    "ManagedPolicyArns": [
                        "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
                    ]
                }
            },
            "ImageProcessingFunction": {
                "Type": "AWS::Lambda::Function",
                "Properties": {
                    "FunctionName": {
                        "Fn::Sub": "${BucketNamePrefix}-processor"
                    },
                    "Runtime": "python3.9",
                    "Handler": "index.lambda_handler",
                    "Role": {
                        "Fn::GetAtt": "LambdaExecutionRole.Arn"
                    },
                    "Timeout": 30,
                    "MemorySize": 256,
                    "Environment": {
                        "Variables": {
                            "DESTINATION_BUCKET": {
                                "Ref": "DestinationBucket"
                            }
                        }
                    },
                    "Code": {
                        "ZipFile": """import boto3, os\ndef lambda_handler(event, context):\n    s3 = boto3.client('s3')\n    dest = os.environ['DESTINATION_BUCKET']\n    bucket = event['Records'][0]['s3']['bucket']['name']\n    key = event['Records'][0]['s3']['object']['key']\n    s3.copy_object(CopySource={'Bucket': bucket, 'Key': key}, Bucket=dest, Key=f'processed/{key}')\n    return {'statusCode': 200}"""
                    }
                }
            }
        },
        "Outputs": {
            "SourceBucketName": {
                "Description": "Source S3 Bucket Name",
                "Value": {"Ref": "SourceBucket"}
            },
            "DestinationBucketName": {
                "Description": "Destination S3 Bucket Name",
                "Value": {"Ref": "DestinationBucket"}
            },
            "LambdaFunctionArn": {
                "Description": "Lambda Function ARN",
                "Value": {"Fn::GetAtt": "ImageProcessingFunction.Arn"}
            }
        }
    }

    try:
        # Create the stack
        response = cf_client.create_stack(
            StackName=STACK_NAME,
            TemplateBody=json.dumps(template_body),
            Capabilities=['CAPABILITY_IAM'],
            EnableTerminationProtection=False
        )

        print(f"Stack creation initiated: {response['StackId']}")

        # Wait for stack creation to complete
        waiter = cf_client.get_waiter('stack_create_complete')
        waiter.wait(StackName=STACK_NAME)

        print(f"Stack '{STACK_NAME}' created successfully!")
        return True

    except ClientError as e:
        print(f"Error creating stack: {e}")
        return False


def delete_cloudformation_stack():
    """Delete the CloudFormation stack and all resources"""
    print(f"\n=== Deleting CloudFormation Stack: {STACK_NAME} ===")

    try:
        cf_client.delete_stack(StackName=STACK_NAME)
        waiter = cf_client.get_waiter('stack_delete_complete')
        waiter.wait(StackName=STACK_NAME)
        print(f"Stack '{STACK_NAME}' deleted successfully!")
        return True
    except ClientError as e:
        print(f"Error deleting stack: {e}")
        return False


def describe_stack_resources():
    """Describe resources in the stack"""
    print(f"\n=== Stack Resources for: {STACK_NAME} ===")

    try:
        response = cf_client.describe_stack_resources(StackName=STACK_NAME)

        for resource in response['StackResources']:
            print(f"  - {resource['LogicalResourceId']}: {resource['ResourceType']} ({resource['ResourceStatus']})")

    except ClientError as e:
        print(f"Error describing stack: {e}")


def update_lambda_function(function_name, new_code_zip):
    """
    Update Lambda function code.
    Demonstrates infrastructure updates through code.
    """
    print(f"\n=== Updating Lambda Function: {function_name} ===")

    try:
        # Create updated code zip
        zip_buffer = io.BytesIO()
        with zipfile.ZipFile(zip_buffer, 'w', zipfile.ZIP_DEFLATED) as zf:
            zf.writestr("index.py", new_code_zip)

        zip_buffer.seek(0)

        lambda_client.update_function_code(
            FunctionName=function_name,
            ZipFile=zip_buffer.read()
        )

        print(f"Function '{function_name}' updated successfully!")
        return True

    except ClientError as e:
        print(f"Error updating function: {e}")
        return False


